  render: ({ event, resolve }) => {
    const payload = (event.value ?? {}) as {
      topic?: string;
      attendee?: string;
    };
    return (
      <TimePickerCard
        topic={payload.topic ?? "a call"}
        attendee={payload.attendee}
        slots={DEFAULT_SLOTS}
        onSubmit={(result) => resolve(result)}
      />
    );
  },
});

