"use client";

// Headless Interrupt cell — no <CopilotChat>, no `useInterrupt` render prop.
//
// As of this commit, the v2 surface does not expose a render-less variant of
// `useInterrupt` (the `render` callback is required in `UseInterruptConfig`),
// nor does `useAgent({ agentId })` surface the current interrupt state or a
// `respond()` helper — it only returns `{ agent }`.
//
// What IS exposed, however, are the lower-level primitives that `useInterrupt`
// composes internally:
//   * `agent.subscribe({ onCustomEvent, onRunStartedEvent, onRunFinalized, onRunFailed })`
//     — AG-UI agent event subscription, available on every `AbstractAgent`.
//   * `copilotkit.runAgent({ agent, forwardedProps: { command: { resume, interruptEvent } } })`
//     — the same call `useInterrupt`'s `resolve()` uses to resume the paused run.
//
// This cell demonstrates using those primitives directly to build a headless
// interrupt resolver: a plain button grid listens for the `on_interrupt` custom
// event, stores the payload, and resolves with the user's chosen slot.

import React, { useEffect, useMemo, useState } from "react";
import { CopilotKit, useAgent, useCopilotKit } from "@copilotkit/react-core/v2";

const INTERRUPT_EVENT_NAME = "on_interrupt";

type InterruptPayload = {
  topic?: string;
  attendee?: string;
};

type InterruptEvent = {
  name: string;
  value: InterruptPayload;
};

type TimeSlot = { label: string; iso: string };

const DEFAULT_SLOTS: TimeSlot[] = [
  { label: "Tomorrow 10:00 AM", iso: "2026-04-19T10:00:00-07:00" },
  { label: "Tomorrow 2:00 PM", iso: "2026-04-19T14:00:00-07:00" },
  { label: "Monday 9:00 AM", iso: "2026-04-21T09:00:00-07:00" },
  { label: "Monday 3:30 PM", iso: "2026-04-21T15:30:00-07:00" },
];

export default function InterruptHeadlessDemo() {
  return (
    <CopilotKit runtimeUrl="/api/copilotkit" agent="interrupt-headless">
      <div className="flex justify-center items-start min-h-screen w-full p-6 bg-gray-50">
        <div className="w-full max-w-3xl">
          <HeadlessInterruptPanel />
        </div>
      </div>
    </CopilotKit>
  );
}

function useHeadlessInterrupt(agentId: string): {
  pending: InterruptEvent | null;
  resolve: (response: unknown) => void;
} {
  const { copilotkit } = useCopilotKit();
  const { agent } = useAgent({ agentId });
  const [pending, setPending] = useState<InterruptEvent | null>(null);

  useEffect(() => {
    let local: InterruptEvent | null = null;
    const sub = agent.subscribe({
      onCustomEvent: ({ event }) => {
        if (event.name === INTERRUPT_EVENT_NAME) {
          local = {
            name: event.name,
            value: (event.value ?? {}) as InterruptPayload,
          };
        }
      },
      onRunStartedEvent: () => {
        local = null;
        setPending(null);
      },
      onRunFinalized: () => {
        if (local) {
          setPending(local);
          local = null;
        }
      },
      onRunFailed: () => {
        local = null;
      },
    });
    return () => sub.unsubscribe();
  }, [agent]);

  const resolve = useMemo(
    () => (response: unknown) => {
      const snapshot = pending;
      setPending(null);
      void copilotkit
        .runAgent({
          agent,
          forwardedProps: {
            command: {
              resume: response,
              interruptEvent: snapshot?.value,
            },
          },
        })
        .catch(() => {});
    },
    [agent, copilotkit, pending],
  );

  return { pending, resolve };
}

function HeadlessInterruptPanel() {
  const { copilotkit } = useCopilotKit();
  const { agent } = useAgent({ agentId: "interrupt-headless" });
  const { pending, resolve } = useHeadlessInterrupt("interrupt-headless");

  const kickOff = (prompt: string) => {
    if (agent.isRunning) return;
    agent.addMessage({
      id: crypto.randomUUID(),
      role: "user",
      content: prompt,
    });
    void copilotkit.runAgent({ agent }).catch(() => {});
  };

  const lastAssistant = [...agent.messages]
    .reverse()
    .find((m) => m.role === "assistant" && typeof m.content === "string") as
    | { content: string }
    | undefined;

  return (
    <div className="flex flex-col gap-4">
      <header>
        <h1 className="text-xl font-semibold text-gray-900">
          Headless Interrupt (no chat, no render prop)
        </h1>
        <p className="mt-1 text-sm text-gray-600">
          Trigger the backend <code>schedule_meeting</code> tool, then resolve
          its <code>interrupt()</code> from the button grid below.
        </p>
      </header>

      <section className="rounded-xl border border-gray-200 bg-white p-4">
        <h2 className="text-sm font-semibold text-gray-900">
          1. Kick off a run
        </h2>
        <div className="mt-3 flex flex-wrap gap-2">
          <button
            className="rounded-lg bg-blue-600 px-3 py-2 text-sm font-medium text-white disabled:opacity-50"
            onClick={() =>
              kickOff(
                "Book an intro call with the sales team to discuss pricing.",
              )
            }
            disabled={agent.isRunning || pending !== null}
          >
            Book sales intro
          </button>
          <button
            className="rounded-lg bg-blue-600 px-3 py-2 text-sm font-medium text-white disabled:opacity-50"
            onClick={() =>
              kickOff("Schedule a 1:1 with Alice next week to review Q2 goals.")
            }
            disabled={agent.isRunning || pending !== null}
          >
            Schedule 1:1 with Alice
          </button>
        </div>
      </section>

      <section className="rounded-xl border border-gray-200 bg-white p-4">
        <h2 className="text-sm font-semibold text-gray-900">
          2. Resolve the interrupt
        </h2>
        {pending ? (
          <>
            <p className="mt-1 text-xs text-gray-500">
              Interrupt received for{" "}
              <span className="font-medium text-gray-800">
                {pending.value.topic ?? "a call"}
              </span>
              {pending.value.attendee ? (
                <>
                  {" "}
                  with{" "}
                  <span className="font-medium text-gray-800">
                    {pending.value.attendee}
                  </span>
                </>
              ) : null}
              . Pick a slot to resume the run.
            </p>
            <div className="mt-3 grid grid-cols-2 gap-2">
              {DEFAULT_SLOTS.map((slot) => (
                <button
                  key={slot.iso}
                  className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 hover:bg-gray-50"
                  onClick={() =>
                    resolve({
                      chosen_time: slot.iso,
                      chosen_label: slot.label,
                    })
                  }
                >
                  {slot.label}
                </button>
              ))}
              <button
                className="col-span-2 rounded-lg border border-gray-300 bg-gray-50 px-3 py-2 text-sm text-gray-700 hover:bg-gray-100"
                onClick={() => resolve({ cancelled: true })}
              >
                Cancel
              </button>
            </div>
          </>
        ) : (
          <p className="mt-1 text-xs text-gray-500">
            No interrupt pending. Kick off a run above.
          </p>
        )}
      </section>

      <section className="rounded-xl border border-gray-200 bg-white p-4">
        <h2 className="text-sm font-semibold text-gray-900">3. Result</h2>
        <div className="mt-2 text-xs text-gray-500">
          Status:{" "}
          <span className="font-medium text-gray-800">
            {agent.isRunning
              ? "running"
              : pending
                ? "awaiting interrupt"
                : "idle"}
          </span>
        </div>
        {lastAssistant?.content ? (
          <div className="mt-2 rounded-lg bg-gray-100 p-3 text-sm text-gray-900 whitespace-pre-wrap">
            {lastAssistant.content}
          </div>
        ) : (
          <div className="mt-2 text-xs text-gray-400">
            Agent response will appear here once the interrupt is resolved.
          </div>
        )}
      </section>
    </div>
  );
}

import { NextRequest, NextResponse } from "next/server";
import {
  CopilotRuntime,
  ExperimentalEmptyAdapter,
  copilotRuntimeNextJSAppRouterEndpoint,
} from "@copilotkit/runtime";
import { LangGraphAgent } from "@copilotkit/runtime/langgraph";

const LANGGRAPH_URL =
  process.env.LANGGRAPH_DEPLOYMENT_URL || "http://localhost:8123";

console.log("[copilotkit/route] Initializing CopilotKit runtime");
console.log(`[copilotkit/route] LANGGRAPH_URL: ${LANGGRAPH_URL}`);
console.log(
  `[copilotkit/route] LANGSMITH_API_KEY: ${process.env.LANGSMITH_API_KEY ? "set" : "not set"}`,
);

function createAgent(graphId: string = "sample_agent") {
  return new LangGraphAgent({
    deploymentUrl: LANGGRAPH_URL,
    graphId,
    langsmithApiKey: process.env.LANGSMITH_API_KEY || "",
  });
}

// Cells that share the neutral default "helpful, concise assistant" graph.
// These cells are chrome / UI / docs demos — the agent has no specialized
// behavior. Each still gets its own registered name so per-cell frontend
// tool/component registrations scope correctly.
const neutralAssistantCells = [
  "human_in_the_loop",
  "shared-state-read",
  "shared-state-write",
  "prebuilt-sidebar",
  "prebuilt-popup",
  "prebuilt-chat",
  "chat-slots",
  "chat-customization-css",
  "headless-simple",
  // NOTE: `beautiful-chat` is NOT in this list — it has its own dedicated
  // runtime at /api/copilotkit-beautiful-chat (needed for openGenerativeUI +
  // a2ui + mcpApps combined-runtime shape). See the beautiful-chat page.tsx.
];

const agents: Record<string, LangGraphAgent> = {};
for (const name of neutralAssistantCells) {
  agents[name] = createAgent();
}

// Dedicated-graph agents.
agents["tool-rendering"] = createAgent("tool_rendering");
agents["tool-rendering-default-catchall"] = createAgent("tool_rendering");
agents["tool-rendering-custom-catchall"] = createAgent("tool_rendering");
agents["tool-rendering-reasoning-chain"] = createAgent(
  "tool_rendering_reasoning_chain",
);
// Frontend-tools variant: no backend tools; the frontend owns the tool.
agents["tool-rendering-frontend-tools"] = createAgent(
  "tool_rendering_frontend_tools",
);
// Declarative Generative UI (A2UI — Dynamic Schema) demo uses its own graph.
agents["declarative-gen-ui"] = createAgent("a2ui_dynamic");
// Hardcoded-catalog variant of dynamic-schema A2UI.
agents["declarative-gen-ui-hardcoded"] = createAgent("a2ui_dynamic_hardcoded");
// Declarative Generative UI (A2UI — Fixed Schema) demo.
agents["a2ui-fixed-schema"] = createAgent("a2ui_fixed");
// Dedicated graphs for stub cells (ported from 4084).
agents["shared-state-streaming"] = createAgent("shared_state_streaming");
agents["subagents"] = createAgent("subagents");
// Basic cells with their own dedicated graphs (neutral assistant variants
// split out of main.py so main.py stays a pure default).
agents["agentic_chat"] = createAgent("agentic_chat");
agents["frontend_tools"] = createAgent("frontend_tools");
agents["gen-ui-agent"] = createAgent("gen_ui_agent");
// Tool-Based Generative UI — chart-viz system prompt lives in its own graph.
agents["gen-ui-tool-based"] = createAgent("gen_ui_tool_based");
// Reasoning variants.
agents["agentic-chat-reasoning"] = createAgent("reasoning_agent");
agents["reasoning-default-render"] = createAgent("reasoning_agent");
// Interrupt variants.
agents["gen-ui-interrupt"] = createAgent("interrupt_agent");
agents["interrupt-headless"] = createAgent("interrupt_agent");
// HITL dedicated (tools=[] + tailored system prompt).
agents["hitl-in-chat"] = createAgent("hitl_in_chat");
// Shared state R+W and read-only agent context.
agents["shared-state-read-write"] = createAgent("shared_state_read_write");
agents["readonly-state-agent-context"] = createAgent(
  "readonly_state_agent_context",
);

// Also register a default
agents["default"] = createAgent();

console.log(
  `[copilotkit/route] Registered ${Object.keys(agents).length} agent names: ${Object.keys(agents).join(", ")}`,
);

export const POST = async (req: NextRequest) => {
  const url = req.url;
  const contentType = req.headers.get("content-type");
  console.log(`[copilotkit/route] POST ${url} (content-type: ${contentType})`);

  try {
    const { handleRequest } = copilotRuntimeNextJSAppRouterEndpoint({
      endpoint: "/api/copilotkit",
      serviceAdapter: new ExperimentalEmptyAdapter(),
      runtime: new CopilotRuntime({
        // @ts-ignore -- Published CopilotRuntime agents type wraps Record in MaybePromise<NonEmptyRecord<...>> which rejects plain Records; fixed in source, pending release
        agents,
        // injectA2UITool wires the A2UI middleware and adds `render_a2ui` +
        // usage guidelines to each listed agent's tool list. The middleware
        // also serialises the registered client catalog (see the frontend
        // `a2ui/renderers` directory) into the agent's `copilotkit.context`
        // so the LLM knows which components + props are available.
        // Scoped to only the A2UI demos so non-A2UI agents don't get the
        // A2UI tool injected.
        a2ui: {
          injectA2UITool: true,
          agents: [
            "declarative-gen-ui",
            "declarative-gen-ui-hardcoded",
            "a2ui-fixed-schema",
          ],
        },
        // NOTE: OpenGenerativeUI is intentionally NOT enabled here — it
        // lives in /api/copilotkit-ogui so non-OGUI agents keep their
        // per-demo `useFrontendTool` / `useComponent` registrations.
        // MCP Apps is in /api/copilotkit-mcp-apps for the same reason.
      }),
    });

    const response = await handleRequest(req);
    console.log(`[copilotkit/route] Response status: ${response.status}`);
    return response;
  } catch (error: any) {
    console.error(`[copilotkit/route] ERROR: ${error.message}`);
    console.error(`[copilotkit/route] Stack: ${error.stack}`);
    return NextResponse.json(
      { error: error.message, stack: error.stack },
      { status: 500 },
    );
  }
};

export const GET = async () => {
  console.log("[copilotkit/route] GET /api/copilotkit (health probe)");

  let langGraphStatus = "unknown";
  try {
    const res = await fetch(`${LANGGRAPH_URL}/ok`, {
      signal: AbortSignal.timeout(3000),
    });
    langGraphStatus = res.ok ? "reachable" : `error (${res.status})`;
  } catch (e: any) {
    langGraphStatus = `unreachable (${e.message})`;
  }

  return NextResponse.json({
    status: "ok",
    langgraph_url: LANGGRAPH_URL,
    langgraph_status: langGraphStatus,
    env: {
      OPENAI_API_KEY: process.env.OPENAI_API_KEY ? "set" : "NOT SET",
      LANGSMITH_API_KEY: process.env.LANGSMITH_API_KEY ? "set" : "NOT SET",
      NODE_ENV: process.env.NODE_ENV,
    },
  });
};

